local LxBaseMgr = require("LApp.Manager.LxBaseMgr")
---@class LxMapMgr:LxBaseMgr
local LxMapMgr = classX("LxMapMgr", LxBaseMgr)

local typeOfGameObject = typeof(UnityEngine.GameObject)
local GameObject = UnityEngine.GameObject

function LxMapMgr:Initialize()
    LxBaseMgr.Initialize(self)
end

function LxMapMgr:Dispose()
    LxBaseMgr.Dispose(self)
end

function LxMapMgr:LoadMap(scene, mapName, onLoadMap)
    local assetPath = "Map/".. mapName.."/"..mapName..".prefab"
    local requester = LxResUtil.GetAssetRequester(assetPath, typeOfGameObject, function(obj)
        if self._isDisposed then return end
        
        if obj ~= nil then
            if LOG_INFO_ENABLED then
                printInfo(PANEL_LOG_TAG, "LoadMap::>>"..mapName.." ok !!!")
            end
            -- new map
            local gameObj = self:CreateMapInternal(scene, mapName, obj)
            -- callback load
            onLoadMap(gameObj)
        else
            if LOG_INFO_ENABLED then
                printInfo(PANEL_LOG_TAG, "LoadMap::>>"..mapName.." failed !!!")
            end
        end
    end)
    return requester
end

function LxMapMgr:CreateMapInternal(scene, mapName, prefab)
    local gameObj = LxResUtil.NewObject(prefab)
    gameObj.name = mapName
    local transform = gameObj.transform
    local mapLayer = FindObject("SceneRoot/LayerMap")
    if mapLayer then
        transform:SetParent(mapLayer.transform)
    end
    transform.localScale = Vector3.one
    transform.localPosition = Vector3.zero
    return gameObj
end

return LxMapMgr
